import { IMessageComposer } from '@nitrots/nitro-renderer';

export class CreateGangComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(name: string, primaryColor: string, secondaryColor: string) {
        this._data = [name, primaryColor, secondaryColor];
        console.log('[📤] CreateGangComposer packet sent:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}